create table if not exists source_cursor (source text primary key check(source in ('wifi','ble')), collector_run_id text not null, spool_sequence integer not null check(spool_sequence>=0), last_event_time text);
create table if not exists metric_event (id integer primary key, source text not null check(source in ('wifi','ble')), summary_id text not null unique, spool_sequence integer not null check(spool_sequence>=0), event_time text not null, payload_json text not null, unique(source,summary_id));
create table if not exists active_session (source text not null check(source in ('wifi','ble')), device_token text not null, payload_json text not null, primary key(source,device_token));
create table if not exists closed_session (id integer primary key, source text not null check(source in ('wifi','ble')), device_token text not null, occurred_at text not null, dwell_seconds numeric not null check(dwell_seconds>=0));
create table if not exists fixed_device (source text not null check(source in ('wifi','ble')), device_token text not null, last_observed_at text not null, fixed_until text not null, primary key(source,device_token));
create table if not exists source_health (source text primary key check(source in ('wifi','ble')), health text not null check(health in ('healthy','degraded','recovering','unavailable')), observed_at text not null);
create table if not exists state_snapshot (snapshot_at text primary key, processed_through text not null, canonical_state_json text not null, config_generation integer not null);
create table if not exists config_snapshot (generation integer primary key, threshold_version text not null, content_digest text not null, canonical_config_json text not null, state text not null check(state in ('pending','active','superseded','rejected','cancelled')), activation_token text not null, activation_boot_id text, deadline_boottime_ns integer, requested_at text not null, acknowledged_at text, rejection_reason text);
create unique index if not exists config_snapshot_one_active on config_snapshot(state) where state='active';
create unique index if not exists config_snapshot_one_pending on config_snapshot(state) where state='pending';
create table if not exists bucket_metric (bucket_start text primary key, bucket_end text not null, payload_json text not null, estimated_people_count integer not null check(estimated_people_count>=0), peak_people_count integer not null check(peak_people_count>=0), revision integer not null check(revision>0));
create table if not exists upload_outbox (bucket_start text primary key, payload_json text not null, state text not null check(state in ('pending','delivered','terminal_rejected')), revision integer not null check(revision>0));
create table if not exists sensor_status (singleton integer primary key check(singleton=1), payload_json text not null, updated_at text not null);
create table if not exists recovery_event (id integer primary key, component text not null, from_health text, to_health text not null, occurred_at text not null, reason text not null);
create table if not exists late_quarantine (id integer primary key, source text not null check(source in ('wifi','ble')), summary_id text not null unique, payload_json text not null, reason text not null, quarantined_at text not null);
